@runtime.tool()
def process_order_payment(order_id: str, amount: float) -> dict:
    """Process payment with idempotency checks"""
    # Idempotency key prevents duplicate charges
    idempotency_key = f"order-{order_id}"
    response = crm_api.charge(
        order_id=order_id,
        amount=amount,
        idempotency_key=idempotency_key
    )
    return {
        "status": response.status,
        "transaction_id": response.transaction_id,
        "rollback_possible": response.refundable
    }

@runtime.tool()
def update_order_status(order_id: str, status: str) -> dict:
    """Update CRM order status idempotently"""
    return erp_api.update_order(order_id, status)

@runtime.tool()
def request_human_approval(order_id: str, reason: str) -> dict:
    """Request human review and wait for approval"""
    approval_request = {
        "order_id": order_id,
        "reason": reason,
        "status": "pending",
        "timestamp": datetime.utcnow()
    }

    # Send to approval queue
    approval_queue.send(approval_request)

    # Agent waits for approval signal
    while approval_request["status"] == "pending":
        time.sleep(5)
        approval_request = approval_queue.poll(order_id)

    return approval_request

@runtime.tool()
def rollback_transaction(transaction_id: str) -> dict:
    """Rollback failed transactions"""
    try:
        refund = payment_api.refund(transaction_id)
        erp_api.update_order_status(transaction_id.split('-')[1], "failed_rollback")
        return {"success": True, "refund_id": refund.id}
    except Exception as e:
        logger.error(f"Rollback failed: {e}")
        return {"success": False, "error": str(e)}

