permission_guardrail = Guardrail(
    name="permission_validation",
    checks=[
        "user.has_required_role",
        "operation.within_scope",
        "no_privilege_escalation"
    ]
)

def verify_permissions(user_id: str, action: dict):
    result = verify(
        action,
        guardrails=[permission_guardrail],
        context={
            "user_id": user_id,
            "user_roles": get_user_roles(user_id),
            "action_type": action.get("type")
        }
    )
    return result.approved
